/*
 * Read a line from serial into buffer with strict bounds checking.
 * Returns the number of characters read (excluding null terminator),
 * or -1 on error/timeout with no data.
 */
static int read_serial_line(char *buf, size_t buf_size)
{
    size_t idx = 0;
    int ch;

    if (buf == NULL || buf_size < 2) {
        return -1;
    }

    while (idx < buf_size - 1) {
        ch = serial_read_char(SERIAL_TIMEOUT_MS);

        if (ch < 0) {
            /* Timeout or error */
            if (idx == 0) {
                return -1;
            }
            break;
        }

        /* Ignore carriage return */
        if (ch == '\r') {
            continue;
        }

        /* Newline terminates the command */
        if (ch == '\n') {
            break;
        }

        /* Only accept printable ASCII characters */
        if (ch < 0x20 || ch > 0x7E) {
            continue;
        }

        buf[idx] = (char)ch;
        idx++;
    }

    buf[idx] = '\0';

    /* If we filled the buffer without finding a newline, discard remaining */
    if (idx == buf_size - 1) {
        send_response("WARN", "Command truncated (too long)");
        /* Drain remaining characters until newline or timeout */
        do {
            ch = serial_read_char(SERIAL_TIMEOUT_MS);
        } while (ch >= 0 && ch != '\n');
    }

    return (int)idx;
}

